function setText(el, text) {
  el.textContent = text;
  return el.textContent;
}

function addClass(el, className) {
  el.classes.push(className);
  return el.classes;
}

function removeClass(el, className) {
  return el.classes.filter((cls) => cls !== className);
}

function updateElement(el, update) {
  return {
    textContent: update.text,
    classes: [...el.classes, update.className],
  };
}
